sql:
SELECT title, rating, (prep_time + cook_time) AS total_time
FROM recipes
ORDER BY rating DESC;

SELECT title, rating
FROM recipes
ORDER BY rating DESC;

SELECT AVG(rating_value) AS average_rating
FROM recipe_ratings
WHERE recipe_id = 1;

SELECT AVG(rating_value) AS average_rating
FROM recipe_ratings
WHERE rating_value != 5;

SELECT title
FROM recipes
WHERE recipe_id IN (SELECT recipe_id FROM recipe_ratings);

external_knowledge:
- "shimmering stars" refers to highly-rated recipes;
- "rating threshold of 3.0" means the recipes' ratings are greater than 3.0;
- "average brilliance" refers to the average rating of the recipes.
